What is the output?

console.log(x);
var x = 5;

What is the output?

const arr = [1, 2, 3];
arr.forEach(n => console.log(n * 2));
const doubled = arr.map(n => n * 2);
console.log(doubled);

What is the output?

for (var i = 0; i < 3; i++) {
  setTimeout(() => console.log(i), 0);
}
for (let j = 0; j < 3; j++) {
  setTimeout(() => console.log(j), 0);
}

What is the output?

function greet(name, greeting) {
  return `${greeting}, ${name}!`;
}
const sayHi = greet.bind(null, 'Alice');
console.log(sayHi('Good morning'));

What is the output?

function outer() {
  let count = 0;
  return function inner() {
    count++;
    return count;
  };
}
const counter = outer();
console.log(counter());
console.log(counter());
console.log(counter());

What is the output?

function curriedAdd(a) {
  return function(b) {
    return function(c) {
      return a + b + c;
    };
  };
}
console.log(curriedAdd(1)(2)(3));
